import React, { createContext, useContext, useState, ReactNode } from 'react';
import { AuthState, User } from '../types';

const AuthContext = createContext<AuthState | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);

  const login = (email: string, name: string) => {
    // Simulate login
    setUser({ email, name });
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, isAuthenticated: !!user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const getChatResponse = async (userMessage: string): Promise<string> => {
  if (!apiKey) {
    return "I'm sorry, the AI service is currently unavailable (Missing API Key).";
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userMessage,
      config: {
        systemInstruction: `You are a helpful, polite, and knowledgeable Indian healthcare assistant named 'UpcharSahayak'.
        Your goal is to help users understand generic medicines, their usages, and safety.

        IMPORTANT RULES:
        1. Do NOT provide specific medical diagnoses.
        2. Always advise the user to consult a doctor for serious conditions.
        3. Explain things in simple English suitable for an Indian audience.
        4. If asked about prices, give general estimates in Indian Rupees (₹) based on common knowledge but mention prices vary.
        5. Be concise and friendly.
        `,
      }
    });

    return response.text || "I'm sorry, I couldn't process that request.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I am having trouble connecting to the server right now. Please try again later.";
  }
};

