import React from 'react';
import { Medicine } from '../types';
import { ArrowRight, Activity, Thermometer, ShieldAlert } from 'lucide-react';
import { Link } from 'react-router-dom';

interface MedicineCardProps {
  medicine: Medicine;
}

const MedicineCard: React.FC<MedicineCardProps> = ({ medicine }) => {
  // Determine icon based on category for visual flair
  const getIcon = () => {
    switch(medicine.category) {
        case 'Fever': return <Thermometer className="text-orange-400" size={20} />;
        case 'Pain Relief': return <Activity className="text-red-400" size={20} />;
        default: return <ShieldAlert className="text-teal-400" size={20} />;
    }
  };

  return (
    <Link to={`/medicine/${medicine.id}`} className="block h-full">
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-lg transition-all duration-300 transform hover:-translate-y-1 h-full flex flex-col overflow-hidden group">
        <div className="h-2 bg-gradient-to-r from-pastel-primary to-pastel-secondary"></div>

        <div className="p-6 flex-1 flex flex-col">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-pastel-blue p-2 rounded-full">
                {getIcon()}
            </div>
            <span className="text-xs font-semibold uppercase tracking-wider text-gray-400 bg-gray-50 px-2 py-1 rounded-md">
                {medicine.category}
            </span>
          </div>

          <h3 className="text-xl font-bold text-gray-800 mb-1 group-hover:text-pastel-primary transition-colors">
            {medicine.name}
          </h3>
          <p className="text-sm text-gray-500 mb-4 font-medium">
             (Example: {medicine.brandExample})
          </p>

          <div className="mt-auto pt-4 border-t border-gray-50">
             <div className="flex flex-wrap gap-2 mb-3">
               {medicine.commonUse.slice(0, 3).map((use, idx) => (
                 <span key={idx} className="text-xs bg-pastel-green text-green-800 px-2 py-1 rounded-full">
                   {use}
                 </span>
               ))}
             </div>

             <div className="flex items-center text-pastel-primary text-sm font-bold mt-2">
                View Comparison <ArrowRight size={16} className="ml-1 group-hover:translate-x-1 transition-transform" />
             </div>
          </div>
        </div>
      </div>
    </Link>
  );
};

export default MedicineCard;

import React, { useState } from 'react';
