import React, { useState } from 'react';
import { MEDICINES } from '../constants';
import MedicineCard from '../components/MedicineCard';
import { Search, Filter } from 'lucide-react';
import { MedicineCategory } from '../types';

const HomePage: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  const categories = ['All', ...Object.values(MedicineCategory)];

  const filteredMedicines = MEDICINES.filter(med => {
    const matchesSearch = med.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          med.brandExample.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          med.commonUse.some(u => u.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesCategory = selectedCategory === 'All' || med.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });

  return (
    <div className="pb-20">
      {/* Hero Section */}
      <div className="bg-pastel-blue/30 py-16 px-4 sm:px-6 lg:px-8 mb-10">
        <div className="max-w-4xl mx-auto text-center animate-fade-in">
          <h1 className="text-4xl md:text-5xl font-extrabold text-gray-800 mb-4 tracking-tight">
            Find Affordable <span className="text-pastel-primary">Generic Medicines</span>
          </h1>
          <p className="text-lg text-gray-600 mb-8 max-w-2xl mx-auto">
            Compare prices between top brands and generic alternatives. Save up to 70% on your monthly medical bills in India.
          </p>

          {/* Search Bar */}
          <div className="relative max-w-2xl mx-auto shadow-xl rounded-full">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Search className="h-6 w-6 text-gray-400" />
            </div>
            <input
              type="text"
              className="block w-full pl-12 pr-4 py-4 rounded-full border-2 border-transparent focus:border-pastel-primary focus:ring-0 bg-white text-gray-900 placeholder-gray-400 text-lg transition-all"
              placeholder="Search medicine (e.g. Dolo, Pan 40, Fever)..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Filters */}
        <div className="flex items-center gap-2 overflow-x-auto pb-6 mb-2 scrollbar-hide">
          <Filter className="text-gray-400 mr-2 flex-shrink-0" size={20} />
          {categories.map((cat) => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`whitespace-nowrap px-4 py-2 rounded-full text-sm font-medium transition-all ${
                selectedCategory === cat 
                  ? 'bg-pastel-primary text-white shadow-md' 
                  : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Grid */}
        {filteredMedicines.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredMedicines.map((med, index) => (
              <div key={med.id} className="animate-slide-up" style={{ animationDelay: `${index * 100}ms` }}>
                <MedicineCard medicine={med} />
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-20 text-gray-400">
            <p className="text-xl">No medicines found matching your criteria.</p>
            <p className="text-sm mt-2">Try searching for generic names like 'Paracetamol'.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HomePage;

import React, { useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MEDICINES } from '../constants';
import { ArrowLeft } from 'lucide-react';
import { PriceComparisonBlock, UsageBlock, DosageBlock, DetailsBlock } from '../components/blocks/MedicineDetailBlocks';

const MedicineDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const medicine = MEDICINES.find(m => m.id === id);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [id]);

  if (!medicine) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4">
        <h2 className="text-2xl font-bold text-gray-800 mb-2">Medicine Not Found</h2>
        <Link to="/" className="text-pastel-primary hover:underline">Go back home</Link>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50/50 pb-20 animate-fade-in">
      {/* Header / Breadcrumb */}
      <div className="bg-white border-b border-gray-100 sticky top-16 z-30">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center gap-4">
          <button onClick={() => navigate(-1)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
            <ArrowLeft className="text-gray-600" size={20} />
          </button>
          <div>
             <h1 className="text-xl sm:text-2xl font-bold text-gray-800">{medicine.name}</h1>
             <p className="text-xs sm:text-sm text-gray-500">Generic for {medicine.brandExample}</p>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-8 space-y-6">

        {/* Block 1: Price Comparison (Full Width) */}
        <section className="animate-slide-up" style={{ animationDelay: '100ms' }}>
          <PriceComparisonBlock medicine={medicine} />
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Block 2: Usage */}
          <section className="animate-slide-up" style={{ animationDelay: '200ms' }}>
            <UsageBlock medicine={medicine} />
          </section>

          {/* Block 3: Dosage */}
          <section className="lg:col-span-2 animate-slide-up" style={{ animationDelay: '300ms' }}>
            <DosageBlock medicine={medicine} />
          </section>
        </div>

        {/* Block 4: Details (Full Width) */}
        <section className="animate-slide-up" style={{ animationDelay: '400ms' }}>
          <DetailsBlock medicine={medicine} />
        </section>

      </div>
    </div>
  );
};

export default MedicineDetailPage;

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
