    const fetchOrders = async () => {
        try {
            const orders = await db.getAllOrders();
            if (orders.length > 0) {
                // Get the most recent order
                const sorted = orders.sort((a, b) => b.createdAt - a.createdAt);
                setLatestOrder(sorted[0]);
            }
        } catch (e) {
            console.error("Failed to fetch orders", e);
        }
    }
    fetchOrders();
  }, []);

  return (
