import React, { useState } from 'react';
import { Medicine } from '../types';
import { ArrowRight, Activity, Thermometer, ShieldAlert, Heart, ShoppingCart, Check } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useBookmarks } from '../context/BookmarkContext';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';

interface MedicineCardProps {
  medicine: Medicine;
}

const MedicineCard: React.FC<MedicineCardProps> = ({ medicine }) => {
  const { isBookmarked, addBookmark, removeBookmark } = useBookmarks();
  const { addToCart } = useCart();
  const { isAuthenticated } = useAuth();
  const [isAdded, setIsAdded] = useState(false);

  const saved = isBookmarked(medicine.id);

  const toggleBookmark = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (saved) {
      removeBookmark(medicine.id);
    } else {
      addBookmark(medicine.id);
    }
  };

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    addToCart(medicine);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  // Determine icon based on category for visual flair (fallback if image fails or for decoration)
  const getIcon = () => {
    switch(medicine.category) {
        case 'Fever': return <Thermometer className="text-orange-400" size={16} />;
        case 'Pain Relief': return <Activity className="text-red-400" size={16} />;
        default: return <ShieldAlert className="text-teal-400" size={16} />;
    }
  };

