import React, { useState } from 'react';
import { Medicine } from '../types';
import { 
  ArrowRight, Activity, Thermometer, ShieldAlert, Heart, ShoppingCart, Check,
  Flame, Wind, Pill, Droplets, HeartPulse, Sun
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { useBookmarks } from '../context/BookmarkContext';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';

interface MedicineCardProps {
  medicine: Medicine;
}

const MedicineCard: React.FC<MedicineCardProps> = ({ medicine }) => {
  const { isBookmarked, addBookmark, removeBookmark } = useBookmarks();
  const { addToCart } = useCart();
  const { isAuthenticated } = useAuth();
  const [isAdded, setIsAdded] = useState(false);

  const saved = isBookmarked(medicine.id);

  const toggleBookmark = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (saved) {
      removeBookmark(medicine.id);
    } else {
      addBookmark(medicine.id);
    }
  };

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    addToCart(medicine);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  // Determine icon based on category for visual flair
  const getIcon = () => {
    const iconSize = 16;
    switch(medicine.category) {
        case 'Fever': return <Thermometer className="text-orange-500" size={iconSize} />;
        case 'Cold & Flu': return <Thermometer className="text-blue-400" size={iconSize} />;
        case 'Pain Relief': return <Activity className="text-red-500" size={iconSize} />;
        case 'Acidity & Gas': return <Flame className="text-yellow-500" size={iconSize} />;
        case 'Allergy': return <Wind className="text-slate-400" size={iconSize} />;
        case 'Antibiotic': return <Pill className="text-indigo-500" size={iconSize} />;
        case 'Diabetes': return <Droplets className="text-violet-500" size={iconSize} />;
        case 'Heart Health': return <HeartPulse className="text-rose-500" size={iconSize} />;
        case 'Vitamins & Supplements': return <Sun className="text-amber-500" size={iconSize} />;
