import React, { useState } from 'react';
import { Medicine } from '../types';
import { 
  ArrowRight, Activity, Thermometer, ShieldAlert, Heart, ShoppingCart, Check,
  Flame, Wind, Pill, Droplets, HeartPulse, Sun
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { useBookmarks } from '../context/BookmarkContext';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';

interface MedicineCardProps {
  medicine: Medicine;
}

const MedicineCard: React.FC<MedicineCardProps> = ({ medicine }) => {
  const { isBookmarked, addBookmark, removeBookmark } = useBookmarks();
  const { addToCart } = useCart();
  const { isAuthenticated } = useAuth();
  const [isAdded, setIsAdded] = useState(false);

  const saved = isBookmarked(medicine.id);

  const toggleBookmark = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (saved) {
      removeBookmark(medicine.id);
    } else {
      addBookmark(medicine.id);
    }
  };

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    addToCart(medicine);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  // Determine icon based on category for visual flair
  const getIcon = () => {
    const iconSize = 16;
    switch(medicine.category) {
        case 'Fever': return <Thermometer className="text-orange-500" size={iconSize} />;
        case 'Cold & Flu': return <Thermometer className="text-blue-400" size={iconSize} />;
        case 'Pain Relief': return <Activity className="text-red-500" size={iconSize} />;
        case 'Acidity & Gas': return <Flame className="text-yellow-500" size={iconSize} />;
        case 'Allergy': return <Wind className="text-slate-400" size={iconSize} />;
        case 'Antibiotic': return <Pill className="text-indigo-500" size={iconSize} />;
        case 'Diabetes': return <Droplets className="text-violet-500" size={iconSize} />;
        case 'Heart Health': return <HeartPulse className="text-rose-500" size={iconSize} />;
        case 'Vitamins & Supplements': return <Sun className="text-amber-500" size={iconSize} />;
        default: return <ShieldAlert className="text-teal-500" size={iconSize} />;
    }
  };

  return (
    <Link to={`/medicine/${medicine.id}`} className="block h-full group">
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 h-full flex flex-col overflow-hidden relative">

        {/* Image Section */}
        <div className="h-40 overflow-hidden relative bg-gray-100">
           <img 
             src={medicine.imageUrl} 
             alt={`${medicine.name} - Generic equivalent for ${medicine.brandExample}`}
             className="w-full h-full object-cover opacity-90 group-hover:opacity-100 group-hover:scale-105 transition-all duration-500"
           />
           <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent"></div>

           <button
             onClick={toggleBookmark}
             className={`absolute top-3 right-3 p-2 rounded-full shadow-md transition-all z-10 ${
               saved 
                ? 'bg-white text-red-500 hover:bg-red-50' 
                : 'bg-white/80 text-gray-400 hover:text-red-500 hover:bg-white'
             }`}
           >
             <Heart size={18} className={saved ? 'fill-current' : ''} />
           </button>

           <div className="absolute bottom-3 left-3 flex items-center gap-2 z-10">
             <span className="text-xs font-semibold uppercase tracking-wider text-white bg-black/30 backdrop-blur-md px-2.5 py-1 rounded-md border border-white/20 flex items-center gap-1.5 shadow-sm">
                {getIcon()} {medicine.category}
             </span>
           </div>

           {/* Quick Add to Cart Button */}
           {isAuthenticated && (
             <button
               onClick={handleAddToCart}
               className={`absolute bottom-3 right-3 p-2 rounded-full shadow-lg transition-all duration-300 transform z-10 flex items-center gap-2 ${
                 isAdded
                   ? 'bg-green-500 text-white translate-y-0 opacity-100 scale-105'
                   : 'bg-pastel-primary text-white hover:bg-pastel-secondary translate-y-10 opacity-0 group-hover:translate-y-0 group-hover:opacity-100'
               }`}
               title="Add to Cart"
             >
               {isAdded ? <Check size={18} /> : <ShoppingCart size={18} />}
               {isAdded && <span className="text-xs font-bold pr-1 animate-fade-in">Added</span>}
             </button>
           )}
        </div>

        <div className="p-5 flex-1 flex flex-col">
          <h3 className="text-lg font-bold text-gray-800 mb-1 group-hover:text-pastel-primary transition-colors line-clamp-1">
            {medicine.name}
          </h3>
          <p className="text-sm text-gray-500 mb-4 font-medium line-clamp-1">
