          <div className="mt-auto">
             <div className="flex flex-wrap gap-2 mb-4 h-12 overflow-hidden content-start">
               {medicine.commonUse.slice(0, 3).map((use, idx) => (
                 <span key={idx} className="text-[10px] bg-pastel-green text-green-800 px-2 py-1 rounded-full border border-green-100">
                   {use}
                 </span>
               ))}
             </div>

             <div className="pt-3 border-t border-gray-50 flex justify-between items-center">
