        if (isLogin) {
            const res = await login(email, password);
            if (res.success) {
                onClose();
            } else {
                setError(res.error || "Login failed");
            }
        } else {
            const res = await register(name, email, password);
            if (res.success) {
                onClose();
            } else {
                setError(res.error || "Registration failed");
            }
        }
    } catch (err) {
        setError("An unexpected error occurred.");
