import React, { createContext, useContext, useState, useEffect, PropsWithChildren } from 'react';
import { AuthState, User } from '../types';

const AuthContext = createContext<AuthState | undefined>(undefined);

export const AuthProvider = ({ children }: PropsWithChildren) => {
  const [user, setUser] = useState<User | null>(null);

  // Load user from session (basic persistence for reload)
  useEffect(() => {
      const stored = sessionStorage.getItem('medigen_session_user');
      if (stored) {
          try {
              setUser(JSON.parse(stored));
          } catch (e) {
              console.error("Session parse error", e);
          }
      }
  }, []);

  const login = async (email: string, password: string): Promise<{ success: boolean; error?: string }> => {
    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 500));

    if (email === 'admin@medigen.com' && password === 'admin') {
        const adminUser: User = {
            id: 'usr_admin',
            name: 'Super Admin',
            email: 'admin@medigen.com',
            role: 'admin',
            createdAt: Date.now()
        };
        setUser(adminUser);
        sessionStorage.setItem('medigen_session_user', JSON.stringify(adminUser));
        return { success: true };
    }

    // Allow any other user for demo
    if (email && password) {
         const demoUser: User = {
            id: `usr_${Date.now()}`,
            name: email.split('@')[0],
            email: email,
            role: 'user',
            createdAt: Date.now()
        };
        setUser(demoUser);
        sessionStorage.setItem('medigen_session_user', JSON.stringify(demoUser));
        return { success: true };
    }

    return { success: false, error: "Invalid credentials" };
  };

  const register = async (name: string, email: string, password: string): Promise<{ success: boolean; error?: string }> => {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 500));

      const newUser: User = {
          id: `usr_${Date.now()}`,
          name,
          email,
          role: 'user',
          createdAt: Date.now()
      };
      setUser(newUser);
      sessionStorage.setItem('medigen_session_user', JSON.stringify(newUser));
      return { success: true };
  };

  const logout = () => {
    setUser(null);
    sessionStorage.removeItem('medigen_session_user');
  };

  return (
    <AuthContext.Provider value={{ user, isAuthenticated: !!user, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

