import { Medicine, Order, CartItem, Address, ActivityLog, User, EmailLog } from '../types';
import { MEDICINES } from '../constants';

// Keys for localStorage
const DB_KEYS = {
  USERS: 'medigen_db_users',
  ORDERS: 'medigen_db_orders',
  MEDICINES: 'medigen_db_medicines',
  LOGS: 'medigen_db_logs',
  EMAILS: 'medigen_db_emails',
  // Base keys for dynamic user data
  CART_PREFIX: 'medigen_cart_',
  BOOKMARK_PREFIX: 'medigen_bookmarks_'
};

// Simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- INTERNAL HELPERS ---
const getStorage = <T>(key: string, defaultVal: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : defaultVal;
  } catch {
    return defaultVal;
  }
};

const setStorage = <T>(key: string, value: T): void => {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    console.error("Storage Full or Error", e);
  }
};

// --- INITIALIZATION ---
// Ensure Admin user exists on first load
const seedUsers = () => {
    const users = getStorage<User[]>(DB_KEYS.USERS, []);
    const adminExists = users.some(u => u.email === 'admin@medigen.com');
    if (!adminExists) {
        const adminUser: User = {
            id: 'usr_admin',
            name: 'Super Admin',
            email: 'admin@medigen.com',
            password: 'admin', // In a real app, this would be hashed
            role: 'admin',
            createdAt: Date.now()
        };
        users.push(adminUser);
        setStorage(DB_KEYS.USERS, users);
        console.log("Database: Seeded Admin User");
    }
};

seedUsers();

export const db = {
  // --- USER & AUTH ---

  registerUser: async (name: string, email: string, password: string): Promise<User> => {
      await delay(800);
      const users = getStorage<User[]>(DB_KEYS.USERS, []);

      if (users.some(u => u.email.toLowerCase() === email.toLowerCase())) {
          throw new Error("User already exists with this email.");
      }

      const newUser: User = {
          id: `usr_${Date.now()}`,
          name,
          email,
          password, // NOTE: In production, never store plain text passwords!
          role: 'user',
          createdAt: Date.now()
      };

      users.push(newUser);
      setStorage(DB_KEYS.USERS, users);
      await db.logActivity('User Registration', `New user registered: ${email}`);
      return newUser;
  },

  authenticateUser: async (email: string, password: string): Promise<User> => {
      await delay(600);
      const users = getStorage<User[]>(DB_KEYS.USERS, []);
      const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);

      if (!user) {
          throw new Error("Invalid email or password.");
      }

      // Return user without password
      const { password: _, ...safeUser } = user;
      return safeUser as User;
  },

  getUserByEmail: async (email: string): Promise<User | undefined> => {
      await delay(200);
      const users = getStorage<User[]>(DB_KEYS.USERS, []);
      const user = users.find(u => u.email.toLowerCase() === email.toLowerCase());
      if (user) {
           const { password: _, ...safeUser } = user;
           return safeUser as User;
      }
      return undefined;
  },

  // --- MEDICINES ---

  getMedicines: async (): Promise<Medicine[]> => {
    await delay(300);
    const stored = localStorage.getItem(DB_KEYS.MEDICINES);
    if (!stored) {
      setStorage(DB_KEYS.MEDICINES, MEDICINES);
      return MEDICINES;
    }
    return JSON.parse(stored);
  },

  getMedicineById: async (id: string): Promise<Medicine | undefined> => {
    await delay(200);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    return medicines.find(m => m.id === id);
  },

  saveMedicine: async (medicine: Medicine): Promise<void> => {
    await delay(500);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);

    const index = medicines.findIndex(m => m.id === medicine.id);
    if (index >= 0) {
      medicines[index] = medicine;
    } else {
      medicines.push(medicine);
    }

    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Update', `Updated/Added medicine: ${medicine.name}`);
  },

  deleteMedicine: async (id: string): Promise<void> => {
    await delay(400);
    let medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    const name = medicines.find(m => m.id === id)?.name || id;
    medicines = medicines.filter(m => m.id !== id);
    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Delete', `Deleted medicine: ${name}`);
  },

  // --- ORDERS ---

  saveOrder: async (
    items: CartItem[], 
    totalAmount: number, 
    address: Address,
    customerEmail: string
  ): Promise<Order> => {
    await delay(1500);

    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);

    const newOrder: Order = {
      id: `ORD-${Math.floor(10000 + Math.random() * 90000)}`,
      items,
      totalAmount,
      address,
      customerEmail,
      status: 'placed',
      createdAt: Date.now(),
      deliveryTime: '45 mins'
    };

    orders.push(newOrder);
    setStorage(DB_KEYS.ORDERS, orders);

    // Import here to avoid circular dependency issues if possible, or handle externally
    // For this structure, we call the email service which calls db.saveEmail
    const { sendOrderConfirmationEmail } = await import('./emailService');
    sendOrderConfirmationEmail(newOrder).catch(err => console.error("Failed to process email", err));

    return newOrder;
  },

  getOrder: async (orderId: string): Promise<Order | null> => {
    await delay(800); 
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders.find(o => o.id === orderId) || null;
  },

  getAllOrders: async (): Promise<Order[]> => {
    await delay(500);
    return getStorage<Order[]>(DB_KEYS.ORDERS, []);
  },

  updateOrderStatus: async (orderId: string, status: Order['status']): Promise<void> => {
    await delay(400);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    const index = orders.findIndex(o => o.id === orderId);
    if (index >= 0) {
      orders[index].status = status;
      setStorage(DB_KEYS.ORDERS, orders);
      await db.logActivity('Order Update', `Updated order #${orderId} status to ${status}`);
    }
  },

  getOrdersByEmail: async (email: string): Promise<Order[]> => {
    await delay(600);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders
      .filter(o => o.customerEmail && o.customerEmail.toLowerCase() === email.toLowerCase())
      .sort((a, b) => b.createdAt - a.createdAt);
  },

  // --- EMAILS ---

  saveEmail: async (to: string, subject: string, body: string): Promise<void> => {
      const emails = getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
      const newEmail: EmailLog = {
          id: `email_${Date.now()}`,
          to,
          subject,
          body,
          sentAt: Date.now(),
          status: 'sent'
      };
      emails.push(newEmail);
      setStorage(DB_KEYS.EMAILS, emails);
  },

  getEmails: async (): Promise<EmailLog[]> => {
      await delay(200);
      return getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
  },

  // --- LOGS ---

  logActivity: async (action: string, details: string) => {
    const logs = getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      action,
      admin: 'System/Admin',
      timestamp: Date.now(),
      details
    };
    logs.unshift(newLog);
    if (logs.length > 100) logs.pop();
    setStorage(DB_KEYS.LOGS, logs);
  },

  getLogs: async (): Promise<ActivityLog[]> => {
    await delay(300);
    return getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
  },

  // --- CART & BOOKMARKS (New Integrated Methods) ---

  getCart: (userId: string | null): CartItem[] => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    return getStorage<CartItem[]>(key, []);
  },

  saveCart: (userId: string | null, items: CartItem[]): void => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    setStorage(key, items);
  },

  getBookmarks: (userId: string | null): string[] => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    return getStorage<string[]>(key, []);
  },

  saveBookmarks: (userId: string | null, ids: string[]): void => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    setStorage(key, ids);
  }
};

import React, { createContext, useContext, useState, useEffect, PropsWithChildren } from 'react';
import { CartItem, Medicine } from '../types';
import { useAuth } from './AuthContext';
import { db } from '../services/db';

interface CartContextType {
  items: CartItem[];
  addToCart: (medicine: Medicine) => void;
  removeFromCart: (id: string) => void;
  updateQuantity: (id: string, quantity: number) => void;
  clearCart: () => void;
  cartTotal: number;
  itemCount: number;
}

const CartContext = createContext<CartContextType | undefined>(undefined);

export const CartProvider = ({ children }: PropsWithChildren) => {
  const { user } = useAuth();
  const userId = user?.id || null;

  const [items, setItems] = useState<CartItem[]>([]);

  // Load cart on mount or user change
  useEffect(() => {
    const loadedCart = db.getCart(userId);
    setItems(loadedCart);
  }, [userId]);

  // Persist cart on items change
  useEffect(() => {
    db.saveCart(userId, items);
  }, [items, userId]);

  const addToCart = (medicine: Medicine) => {
    setItems(prev => {
      const existing = prev.find(item => item.id === medicine.id);
      if (existing) {
        return prev.map(item => 
          item.id === medicine.id 
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prev, { ...medicine, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
    if (quantity < 1) return;
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, quantity } : item
    ));
  };

  const clearCart = () => setItems([]);

  const cartTotal = items.reduce((total, item) => total + (item.genericPrice * item.quantity), 0);
  const itemCount = items.reduce((count, item) => count + item.quantity, 0);

  return (
    <CartContext.Provider value={{ items, addToCart, removeFromCart, updateQuantity, clearCart, cartTotal, itemCount }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (context === undefined) {
    throw new Error('useCart must be used within a CartProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, PropsWithChildren } from 'react';
import { useAuth } from './AuthContext';
import { db } from '../services/db';

interface BookmarkContextType {
  bookmarks: string[];
  addBookmark: (id: string) => void;
  removeBookmark: (id: string) => void;
  isBookmarked: (id: string) => boolean;
}

const BookmarkContext = createContext<BookmarkContextType | undefined>(undefined);

export const BookmarkProvider = ({ children }: PropsWithChildren) => {
  const { user } = useAuth();
  const userId = user?.id || null;
  const [bookmarks, setBookmarks] = useState<string[]>([]);

  // Load bookmarks on mount or user change
  useEffect(() => {
    const loadedBookmarks = db.getBookmarks(userId);
    setBookmarks(loadedBookmarks);
  }, [userId]);

  // Persist bookmarks on change
  useEffect(() => {
    db.saveBookmarks(userId, bookmarks);
  }, [bookmarks, userId]);

  const addBookmark = (id: string) => {
    setBookmarks((prev) => {
      if (prev.includes(id)) return prev;
      return [...prev, id];
    });
  };

  const removeBookmark = (id: string) => {
    setBookmarks((prev) => prev.filter((bookmarkId) => bookmarkId !== id));
  };

  const isBookmarked = (id: string) => bookmarks.includes(id);

  return (
    <BookmarkContext.Provider value={{ bookmarks, addBookmark, removeBookmark, isBookmarked }}>
      {children}
    </BookmarkContext.Provider>
  );
};

export const useBookmarks = () => {
  const context = useContext(BookmarkContext);
  if (context === undefined) {
    throw new Error('useBookmarks must be used within a BookmarkProvider');
  }
  return context;
};

