import { Medicine, Order, CartItem, Address, ActivityLog, User, EmailLog } from '../types';
import { MEDICINES } from '../constants';

// Keys for localStorage (USERS key removed to disable persistence for auth)
const DB_KEYS = {
  ORDERS: 'medigen_db_orders',
  MEDICINES: 'medigen_db_medicines',
  LOGS: 'medigen_db_logs',
  EMAILS: 'medigen_db_emails',
  CART_PREFIX: 'medigen_cart_',
  BOOKMARK_PREFIX: 'medigen_bookmarks_'
};

// In-Memory Users Store (Reset on reload)
// Pre-seeded with Admin
const MEMORY_USERS: User[] = [
    {
        id: 'usr_admin',
        name: 'Super Admin',
        email: 'admin@medigen.com',
        password: 'admin',
        role: 'admin',
        createdAt: Date.now()
    }
];

// Simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- INTERNAL HELPERS ---
const getStorage = <T>(key: string, defaultVal: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : defaultVal;
  } catch {
    return defaultVal;
  }
};

const setStorage = <T>(key: string, value: T): void => {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    console.error("Storage Full or Error", e);
  }
};

export const db = {
  // --- USER & AUTH (In-Memory Only) ---

  registerUser: async (name: string, email: string, password: string): Promise<User> => {
      await delay(800);

      // Check in-memory list
      if (MEMORY_USERS.some(u => u.email.toLowerCase() === email.toLowerCase())) {
          throw new Error("User already exists with this email.");
      }

      const newUser: User = {
          id: `usr_${Date.now()}`,
          name,
          email,
          password,
          role: 'user',
          createdAt: Date.now()
      };

      MEMORY_USERS.push(newUser);
      // We do not save to localStorage, per request

      await db.logActivity('User Registration', `New user registered: ${email}`);
      return newUser;
  },

  authenticateUser: async (email: string, password: string): Promise<User> => {
      await delay(600);

      const user = MEMORY_USERS.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);

      if (!user) {
          throw new Error("Invalid email or password.");
      }

      // Return user without password
      const { password: _, ...safeUser } = user;
      return safeUser as User;
  },

  getUserByEmail: async (email: string): Promise<User | undefined> => {
      await delay(200);
      const user = MEMORY_USERS.find(u => u.email.toLowerCase() === email.toLowerCase());
      if (user) {
           const { password: _, ...safeUser } = user;
           return safeUser as User;
      }
      return undefined;
  },

  // --- MEDICINES (Persistent) ---

  getMedicines: async (): Promise<Medicine[]> => {
    await delay(300);
    const stored = localStorage.getItem(DB_KEYS.MEDICINES);
    if (!stored) {
      setStorage(DB_KEYS.MEDICINES, MEDICINES);
      return MEDICINES;
    }
    return JSON.parse(stored);
  },

  getMedicineById: async (id: string): Promise<Medicine | undefined> => {
    await delay(200);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    return medicines.find(m => m.id === id);
  },

  saveMedicine: async (medicine: Medicine): Promise<void> => {
    await delay(500);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);

    const index = medicines.findIndex(m => m.id === medicine.id);
    if (index >= 0) {
      medicines[index] = medicine;
    } else {
      medicines.push(medicine);
    }

    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Update', `Updated/Added medicine: ${medicine.name}`);
  },

  deleteMedicine: async (id: string): Promise<void> => {
    await delay(400);
    let medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    const name = medicines.find(m => m.id === id)?.name || id;
    medicines = medicines.filter(m => m.id !== id);
    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Delete', `Deleted medicine: ${name}`);
  },

  // --- ORDERS (Persistent) ---

  saveOrder: async (
    items: CartItem[], 
    totalAmount: number, 
    address: Address,
    customerEmail: string
  ): Promise<Order> => {
    await delay(1500);

    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);

    const newOrder: Order = {
      id: `ORD-${Math.floor(10000 + Math.random() * 90000)}`,
      items,
      totalAmount,
      address,
      customerEmail,
      status: 'placed',
      createdAt: Date.now(),
      deliveryTime: '45 mins'
    };

    orders.push(newOrder);
    setStorage(DB_KEYS.ORDERS, orders);

    // Import here to avoid circular dependency issues if possible, or handle externally
    const { sendOrderConfirmationEmail } = await import('./emailService');
    sendOrderConfirmationEmail(newOrder).catch(err => console.error("Failed to process email", err));

    return newOrder;
  },

  getOrder: async (orderId: string): Promise<Order | null> => {
    await delay(800); 
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders.find(o => o.id === orderId) || null;
  },

  getAllOrders: async (): Promise<Order[]> => {
    await delay(500);
    return getStorage<Order[]>(DB_KEYS.ORDERS, []);
  },

  updateOrderStatus: async (orderId: string, status: Order['status']): Promise<void> => {
    await delay(400);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    const index = orders.findIndex(o => o.id === orderId);
    if (index >= 0) {
      orders[index].status = status;
      setStorage(DB_KEYS.ORDERS, orders);
      await db.logActivity('Order Update', `Updated order #${orderId} status to ${status}`);
    }
  },

  getOrdersByEmail: async (email: string): Promise<Order[]> => {
    await delay(600);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders
      .filter(o => o.customerEmail && o.customerEmail.toLowerCase() === email.toLowerCase())
      .sort((a, b) => b.createdAt - a.createdAt);
  },

  // --- EMAILS (Persistent) ---

  saveEmail: async (to: string, subject: string, body: string): Promise<void> => {
      const emails = getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
      const newEmail: EmailLog = {
          id: `email_${Date.now()}`,
          to,
          subject,
          body,
          sentAt: Date.now(),
          status: 'sent'
      };
      emails.push(newEmail);
      setStorage(DB_KEYS.EMAILS, emails);
  },

  getEmails: async (): Promise<EmailLog[]> => {
      await delay(200);
      return getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
  },

  // --- LOGS (Persistent) ---

  logActivity: async (action: string, details: string) => {
    const logs = getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      action,
      admin: 'System/Admin',
      timestamp: Date.now(),
      details
    };
    logs.unshift(newLog);
    if (logs.length > 100) logs.pop();
    setStorage(DB_KEYS.LOGS, logs);
  },

  getLogs: async (): Promise<ActivityLog[]> => {
    await delay(300);
    return getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
  },

  // --- CART & BOOKMARKS (Persistent) ---

  getCart: (userId: string | null): CartItem[] => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    return getStorage<CartItem[]>(key, []);
  },

  saveCart: (userId: string | null, items: CartItem[]): void => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    setStorage(key, items);
  },

  getBookmarks: (userId: string | null): string[] => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    return getStorage<string[]>(key, []);
  },

  saveBookmarks: (userId: string | null, ids: string[]): void => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    setStorage(key, ids);
  }
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { ShieldCheck, Lock, Mail, ArrowRight, Loader2, AlertCircle, Key } from 'lucide-react';

const AdminLoginPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login, user, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  // If already logged in as admin, redirect to dashboard
  useEffect(() => {
      if (isAuthenticated && user?.role === 'admin') {
          navigate('/admin');
      }
  }, [isAuthenticated, user, navigate]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
        const res = await login(email, password);
        if (res.success) {
            // Check if email matches admin
            if (email === 'admin@medigen.com') {
                navigate('/admin');
            } else {
                setError('Access Denied. Not an admin account.');
            }
        } else {
            setError(res.error || 'Invalid credentials');
        }
    } catch (err) {
        setError('Login failed. Please try again.');
    } finally {
        setLoading(false);
    }
  };

  const fillCredentials = () => {
      setEmail('admin@medigen.com');
      setPassword('admin');
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-pastel-primary/10 rounded-full blur-3xl"></div>
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-blue-500/10 rounded-full blur-3xl"></div>
      </div>

      <div className="w-full max-w-md bg-slate-800 border border-slate-700 rounded-3xl shadow-2xl p-8 relative z-10 animate-fade-in">
        <div className="text-center mb-8">
            <div className="bg-slate-700/50 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-slate-600">
                <ShieldCheck size={32} className="text-pastel-primary" />
            </div>
            <h1 className="text-2xl font-bold text-white mb-2">Admin Portal</h1>
            <p className="text-slate-400 text-sm">Secure access for MediGen staff only</p>
        </div>

        {/* Demo Credentials Block - Added for convenience */}
        <div 
            onClick={fillCredentials}
            className="mb-6 bg-slate-700/30 hover:bg-slate-700/50 cursor-pointer border border-slate-600/50 hover:border-pastel-primary/30 p-3 rounded-xl flex items-center gap-3 transition-all group"
        >
            <div className="bg-slate-800 p-2 rounded-lg group-hover:bg-pastel-primary/20 transition-colors">
                <Key size={16} className="text-slate-400 group-hover:text-pastel-primary" />
            </div>
            <div className="text-left">
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Demo Credentials (Click to fill)</p>
                <p className="text-xs text-slate-300 font-mono mt-0.5">admin@medigen.com <span className="text-slate-600">|</span> admin</p>
            </div>
        </div>

        {error && (
            <div className="mb-6 p-4 bg-red-900/20 border border-red-900/50 rounded-xl flex items-center gap-3 text-red-400 text-sm">
                <AlertCircle size={18} />
                {error}
            </div>
        )}

        <form onSubmit={handleLogin} className="space-y-5">
            <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Email Address</label>
                <div className="relative group">
                    <Mail className="absolute left-4 top-3.5 h-5 w-5 text-slate-500 group-focus-within:text-pastel-primary transition-colors" />
                    <input
                        type="email"
                        required
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:bg-slate-900 focus:ring-2 focus:ring-pastel-primary focus:border-transparent outline-none transition-all font-medium text-slate-200 placeholder-slate-600"
                        placeholder="admin@medigen.com"
                    />
                </div>
            </div>

            <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Password</label>
                <div className="relative group">
                    <Lock className="absolute left-4 top-3.5 h-5 w-5 text-slate-500 group-focus-within:text-pastel-primary transition-colors" />
                    <input
                        type="password"
                        required
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:bg-slate-900 focus:ring-2 focus:ring-pastel-primary focus:border-transparent outline-none transition-all font-medium text-slate-200 placeholder-slate-600"
                        placeholder="••••••••"
                    />
                </div>
            </div>

            <button
                type="submit"
                disabled={loading}
                className="w-full bg-pastel-primary hover:bg-pastel-secondary text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed mt-4"
            >
                {loading ? <Loader2 className="animate-spin" size={20} /> : (
                    <>
                        Access Dashboard <ArrowRight size={18} />
                    </>
                )}
            </button>
        </form>

        <div className="mt-8 pt-6 border-t border-slate-700 text-center">
            <button 
                onClick={() => navigate('/')} 
                className="text-slate-500 hover:text-slate-300 text-sm font-medium transition-colors"
            >
                Back to User Site
            </button>
        </div>
      </div>
    </div>
  );
};

export default AdminLoginPage;

