const sqlite3 = require('sqlite3').verbose();
const path = require('path');

// Create a database file named 'medigen.db'
const dbPath = path.resolve(__dirname, 'medigen.db');
const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
        console.error('Error opening database', err.message);
    } else {
        console.log('Connected to the SQLite database.');
        initDb();
    }
});

function initDb() {
    db.serialize(() => {
        // Create Users Table
        db.run(`CREATE TABLE IF NOT EXISTS users (
            id TEXT PRIMARY KEY,
            name TEXT,
            email TEXT UNIQUE,
            password TEXT,
            role TEXT,
            created_at INTEGER
        )`);

        // Seed Admin User
        const adminEmail = 'admin@medigen.com';
        db.get("SELECT email FROM users WHERE email = ?", [adminEmail], (err, row) => {
            if (!row) {
                const adminUser = {
                    id: 'usr_admin',
                    name: 'Super Admin',
                    email: adminEmail,
                    password: 'admin', // Note: In production, use bcrypt to hash passwords
                    role: 'admin',
                    created_at: Date.now()
                };

                const insert = db.prepare("INSERT INTO users (id, name, email, password, role, created_at) VALUES (?,?,?,?,?,?)");
                insert.run(adminUser.id, adminUser.name, adminUser.email, adminUser.password, adminUser.role, adminUser.created_at);
                insert.finalize();
                console.log("Seeded Admin User");
            }
        });
    });
}

module.exports = db;

const express = require('express');
const cors = require('cors');
const bodyParser = require('body-parser');
const db = require('./database');

const app = express();
const PORT = 5000;

app.use(cors());
app.use(bodyParser.json());

// --- Auth Routes ---

// Register
app.post('/api/register', (req, res) => {
    const { name, email, password } = req.body;

    // Validation
    if (!name || !email || !password) {
        return res.status(400).json({ error: "All fields are required" });
    }

    if (email.toLowerCase() === 'admin@medigen.com') {
        return res.status(403).json({ error: "Restricted email address." });
    }

    const id = `usr_${Date.now()}`;
    const role = 'user';
    const createdAt = Date.now();

    const sql = `INSERT INTO users (id, name, email, password, role, created_at) VALUES (?, ?, ?, ?, ?, ?)`;

    db.run(sql, [id, name, email, password, role, createdAt], function(err) {
        if (err) {
            if (err.message.includes('UNIQUE constraint failed')) {
                return res.status(400).json({ error: "User already exists with this email." });
            }
            return res.status(500).json({ error: err.message });
        }

        // Return user without password
        res.json({
            id,
            name,
            email,
            role,
            createdAt
        });
    });
});

// Login
app.post('/api/login', (req, res) => {
    const { email, password } = req.body;

    const sql = `SELECT * FROM users WHERE email = ? AND password = ?`;

    db.get(sql, [email, password], (err, row) => {
        if (err) {
            return res.status(500).json({ error: err.message });
        }
        if (!row) {
            return res.status(401).json({ error: "Invalid email or password." });
        }

        // Return user without password
        const { password: _, ...user } = row;
        res.json(user);
    });
});

app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
});

