import React, { useState, useEffect } from 'react';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { db } from '../services/db';
import { MapPin, CreditCard, CheckCircle2, Home, Building, Truck, Loader2, Mail } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CheckoutPage: React.FC = () => {
  const { cartTotal, items, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [isProcessing, setIsProcessing] = useState(false);
  const [step, setStep] = useState(1);
  const [addressType, setAddressType] = useState<'home' | 'work'>('home');

  // Billing Constants
  const DELIVERY_THRESHOLD = 200;
  const DELIVERY_FEE = 40;
  const PLATFORM_FEE = 10;
  const GST_RATE = 0.12;

  const gstAmount = cartTotal * GST_RATE;
  const deliveryCharge = cartTotal > DELIVERY_THRESHOLD ? 0 : DELIVERY_FEE;
  const finalTotal = cartTotal + gstAmount + deliveryCharge + PLATFORM_FEE;

  // Form State
  const [formData, setFormData] = useState({
    fullName: user?.name || '',
    email: user?.email || '',
    phone: '',
    line: '',
    city: '',
    pincode: ''
  });

  // Pre-fill user data
  useEffect(() => {
    if (user) {
        setFormData(prev => ({
            ...prev,
            fullName: prev.fullName || user.name,
            email: prev.email || user.email
        }));
    }
  }, [user]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handlePlaceOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    if (items.length === 0) return;

    setIsProcessing(true);

    try {
        const address = {
            fullName: formData.fullName,
            phone: formData.phone,
            line: formData.line,
            city: formData.city,
            pincode: formData.pincode,
            type: addressType
        };

        const newOrder = await db.saveOrder(items, finalTotal, address, formData.email);

        setIsProcessing(false);
        setStep(3); // Success Step

        setTimeout(() => {
            clearCart();
            navigate(`/track-order?orderId=${newOrder.id}`);
        }, 2000);
    } catch (error) {
        console.error("Order Failed", error);
        setIsProcessing(false);
        alert("Failed to place order. Please try again.");
    }
  };

  if (step === 3) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <div className="bg-white p-12 rounded-3xl shadow-lg text-center animate-fade-in max-w-md">
                  <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
                      <CheckCircle2 size={48} className="text-green-600" />
                  </div>
                  <h2 className="text-2xl font-bold text-gray-800 mb-2">Order Confirmed!</h2>
                  <p className="text-gray-500 mb-2">A confirmation email has been sent to:</p>
                  <p className="font-bold text-gray-800 mb-6 bg-gray-50 py-2 px-4 rounded-lg inline-block">{formData.email}</p>

                  <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden mb-2">
                      <div className="bg-green-500 h-full w-full animate-[shimmer_1s_infinite]"></div>
                  </div>
                  <p className="text-xs text-gray-400">Redirecting to order tracking...</p>
              </div>
          </div>
      )
  }

  return (
    <div className="min-h-screen bg-gray-50 py-10">
