/**
 * Simulates a backend email service.
 */
export const sendOrderConfirmationEmail = async (order: Order): Promise<boolean> => {
  // Simulate network latency for email server
  await new Promise(resolve => setTimeout(resolve, 1000));

  const { id, totalAmount, customerEmail } = order;

  // In a real app, this would use an email provider like SendGrid or AWS SES
  const emailBody = `
    <h1>Order Confirmed</h1>
    <p>Thank you for ordering with MediGen.</p>
    <p>Order ID: <strong>${id}</strong></p>
    <p>Total Amount: <strong>₹${totalAmount}</strong></p>
    <p>Status: Placed</p>
  `;

  // Log to our local "database" so Admin can see it
  await db.saveEmail(customerEmail, `Order Confirmation - #${id}`, emailBody);

  console.group('%c📧 [Email Service Simulation] Email Sent', 'color: #0D9488; font-weight: bold; font-size: 14px;');
  console.log(`%cTo: %c${customerEmail}`, 'color: gray', 'color: #333; font-weight: bold');
  console.log(`%cSubject: %cYour Medicine Order is Confirmed – Order #${id}`, 'color: gray', 'color: #333; font-weight: bold');
  console.log(`%cAmount: %c₹${totalAmount}`, 'color: gray', 'color: #333; font-weight: bold');
  console.log('%cStatus: Sent successfully (Logged to DB)', 'color: green');
  console.groupEnd();

  return true;
};

/**
 * Simulates sending a login security alert via Email and SMS.
 */
export const sendLoginAlert = async (user: User): Promise<void> => {
  // Simulate slight delay
  await new Promise(resolve => setTimeout(resolve, 500));

  const emailSubject = `Security Alert: New Login to MediGen`;
  const emailBody = `
    <h1>New Login Detected</h1>
    <p>Hello ${user.name},</p>
    <p>We detected a new login to your MediGen account.</p>
    <p><strong>Time:</strong> ${new Date().toLocaleString()}</p>
    <p>If this wasn't you, please contact support immediately.</p>
  `;

  // 1. Simulate Email
  await db.saveEmail(user.email, emailSubject, emailBody);

  // 2. Simulate SMS (Log to Console)
  const phone = user.phone || 'Active Mobile';
  const smsContent = `MediGen Alert: Login detected for ${user.email} at ${new Date().toLocaleTimeString()}. Not you? Report now.`;

  console.group('%c🚨 [Notification Service] Security Alert Sent', 'color: #ef4444; font-weight: bold; font-size: 14px;');
  console.log(`%cType: %cEmail & SMS`, 'color: gray', 'color: #333; font-weight: bold');
  console.log(`%cTo Email: %c${user.email}`, 'color: gray', 'color: #333; font-weight: bold');
  console.log(`%cTo Phone: %c${phone}`, 'color: gray', 'color: #333; font-weight: bold');
  console.log(`%cSMS Body: %c${smsContent}`, 'color: gray', 'color: #333; font-style: italic;');
  console.groupEnd();

  // 3. Dispatch Event for UI Toast
  window.dispatchEvent(new CustomEvent('medigen-toast', { 
      detail: { 
          title: 'Security Alert Sent',
          message: `Login notification sent to ${user.email} & ${phone}.`,
          type: 'info'
      } 
  }));
};

import { Medicine, Order, CartItem, Address, ActivityLog, User, EmailLog } from '../types';
import { MEDICINES } from '../constants';

// Keys for localStorage
const DB_KEYS = {
  ORDERS: 'medigen_db_orders',
  MEDICINES: 'medigen_db_medicines',
  LOGS: 'medigen_db_logs',
  EMAILS: 'medigen_db_emails',
  USERS: 'medigen_db_users_fallback', // New key for offline users
  // Base keys for dynamic user data
  CART_PREFIX: 'medigen_cart_',
  BOOKMARK_PREFIX: 'medigen_bookmarks_'
};

const API_URL = 'http://localhost:5000/api';

// Simulate network delay for LS operations
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- INTERNAL HELPERS ---
const getStorage = <T>(key: string, defaultVal: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : defaultVal;
  } catch {
    return defaultVal;
  }
};

const setStorage = <T>(key: string, value: T): void => {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    console.error("Storage Full or Error", e);
  }
};

export const db = {
  // --- USER & AUTH (HYBRID: API -> FALLBACK) ---

  registerUser: async (name: string, email: string, phone: string, password: string): Promise<User> => {
      try {
          // 1. Try Backend
          const response = await fetch(`${API_URL}/register`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ name, email, phone, password })
          });

          if (response.ok) {
              const data = await response.json();
              await db.logActivity('User Registration', `New user registered: ${email}`);
              return data as User;
          } else {
             const errData = await response.json().catch(() => ({}));
             throw new Error(errData.error || "Registration failed on server");
          }

      } catch (error: any) {
          console.warn("Backend unavailable or failed, switching to offline mode:", error.message);

          // 2. Local Fallback
          await delay(500);
          const users = getStorage<User[]>(DB_KEYS.USERS, []);

          if (users.find(u => u.email === email)) {
              throw new Error("User already exists (Offline Mode)");
          }

          const newUser: User = {
              id: `usr_local_${Date.now()}`,
              name,
              email,
              phone,
              role: 'user',
              createdAt: Date.now(),
              password: password 
          };

          users.push(newUser);
          setStorage(DB_KEYS.USERS, users);

          const { password: _, ...userReturn } = newUser;
          return userReturn;
      }
  },

  authenticateUser: async (email: string, password: string): Promise<User> => {
      try {
          // 1. Try Backend
          const response = await fetch(`${API_URL}/login`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ email, password })
          });

          if (response.ok) {
              const data = await response.json();
              return data as User;
          } else {
             const errData = await response.json().catch(() => ({}));
             if (response.status === 401) throw new Error("Invalid credentials");
             if (response.status < 500) throw new Error(errData.error || "Login failed");
             throw new Error("Server Error"); // Trigger fallback
          }

      } catch (error: any) {
          console.warn("Backend unavailable, checking local records:", error.message);

          // 2. Local Fallback
          await delay(500);

          // Hardcoded Admin
          if (email === 'admin@medigen.com' && password === 'admin') {
              return {
                  id: 'usr_admin',
                  name: 'Super Admin',
                  email: 'admin@medigen.com',
                  phone: '+91 98765 43210',
                  role: 'admin',
                  createdAt: Date.now()
              };
          }

          // Check Offline Users
          const users = getStorage<User[]>(DB_KEYS.USERS, []);
          const user = users.find(u => u.email === email && u.password === password);

          if (user) {
              const { password: _, ...userReturn } = user;
              return userReturn;
          }

          throw new Error("Invalid credentials or Server Unavailable");
      }
  },

  // --- MEDICINES (LocalStorage) ---

  getMedicines: async (): Promise<Medicine[]> => {
    await delay(300);
    const stored = localStorage.getItem(DB_KEYS.MEDICINES);
    if (!stored) {
      setStorage(DB_KEYS.MEDICINES, MEDICINES);
      return MEDICINES;
    }
    return JSON.parse(stored);
  },

  getMedicineById: async (id: string): Promise<Medicine | undefined> => {
    await delay(200);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    return medicines.find(m => m.id === id);
  },

  saveMedicine: async (medicine: Medicine): Promise<void> => {
    await delay(500);
    const medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);

    const index = medicines.findIndex(m => m.id === medicine.id);
    if (index >= 0) {
      medicines[index] = medicine;
    } else {
      medicines.push(medicine);
    }

    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Update', `Updated/Added medicine: ${medicine.name}`);
  },

  deleteMedicine: async (id: string): Promise<void> => {
    await delay(400);
    let medicines = getStorage<Medicine[]>(DB_KEYS.MEDICINES, MEDICINES);
    const name = medicines.find(m => m.id === id)?.name || id;
    medicines = medicines.filter(m => m.id !== id);
    setStorage(DB_KEYS.MEDICINES, medicines);
    await db.logActivity('Medicine Delete', `Deleted medicine: ${name}`);
  },

  // --- ORDERS (LocalStorage) ---

  saveOrder: async (
    items: CartItem[], 
    totalAmount: number, 
    address: Address,
    customerEmail: string
  ): Promise<Order> => {
    await delay(1500);

    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);

    const newOrder: Order = {
      id: `ORD-${Math.floor(10000 + Math.random() * 90000)}`,
      items,
      totalAmount,
      address,
      customerEmail,
      status: 'placed',
      createdAt: Date.now(),
      deliveryTime: '45 mins'
    };

    orders.push(newOrder);
    setStorage(DB_KEYS.ORDERS, orders);

    const { sendOrderConfirmationEmail } = await import('./emailService');
    sendOrderConfirmationEmail(newOrder).catch(err => console.error("Failed to process email", err));

    return newOrder;
  },

  getOrder: async (orderId: string): Promise<Order | null> => {
    await delay(800); 
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders.find(o => o.id === orderId) || null;
  },

  getAllOrders: async (): Promise<Order[]> => {
    await delay(500);
    return getStorage<Order[]>(DB_KEYS.ORDERS, []);
  },

  updateOrderStatus: async (orderId: string, status: Order['status']): Promise<void> => {
    await delay(400);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    const index = orders.findIndex(o => o.id === orderId);
    if (index >= 0) {
      orders[index].status = status;
      setStorage(DB_KEYS.ORDERS, orders);
      await db.logActivity('Order Update', `Updated order #${orderId} status to ${status}`);
    }
  },

  getOrdersByEmail: async (email: string): Promise<Order[]> => {
    await delay(600);
    const orders = getStorage<Order[]>(DB_KEYS.ORDERS, []);
    return orders
      .filter(o => o.customerEmail && o.customerEmail.toLowerCase() === email.toLowerCase())
      .sort((a, b) => b.createdAt - a.createdAt);
  },

  // --- EMAILS (LocalStorage) ---

  saveEmail: async (to: string, subject: string, body: string): Promise<void> => {
      const emails = getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
      const newEmail: EmailLog = {
          id: `email_${Date.now()}`,
          to,
          subject,
          body,
          sentAt: Date.now(),
          status: 'sent'
      };
      emails.push(newEmail);
      setStorage(DB_KEYS.EMAILS, emails);
  },

  getEmails: async (): Promise<EmailLog[]> => {
      await delay(200);
      return getStorage<EmailLog[]>(DB_KEYS.EMAILS, []);
  },

  // --- LOGS (LocalStorage) ---

  logActivity: async (action: string, details: string) => {
    const logs = getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      action,
      admin: 'System/Admin',
      timestamp: Date.now(),
      details
    };
    logs.unshift(newLog);
    if (logs.length > 100) logs.pop();
    setStorage(DB_KEYS.LOGS, logs);
  },

  getLogs: async (): Promise<ActivityLog[]> => {
    await delay(300);
    return getStorage<ActivityLog[]>(DB_KEYS.LOGS, []);
  },

  // --- CART & BOOKMARKS (LocalStorage) ---

  getCart: (userId: string | null): CartItem[] => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    return getStorage<CartItem[]>(key, []);
  },

  saveCart: (userId: string | null, items: CartItem[]): void => {
    const key = userId ? `${DB_KEYS.CART_PREFIX}${userId}` : 'medigen_cart_guest';
    setStorage(key, items);
  },

  getBookmarks: (userId: string | null): string[] => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    return getStorage<string[]>(key, []);
  },

  saveBookmarks: (userId: string | null, ids: string[]): void => {
    const key = userId ? `${DB_KEYS.BOOKMARK_PREFIX}${userId}` : 'medigen_bookmarks_guest';
    setStorage(key, ids);
  },

  getUserByEmail: async (email: string): Promise<User | undefined> => {
      const users = getStorage<User[]>(DB_KEYS.USERS, []);
      const user = users.find(u => u.email === email);
      if (user) {
          const { password: _, ...userReturn } = user;
          return userReturn;
      }
      return undefined; 
  },
};

import React, { createContext, useContext, useState, useEffect, PropsWithChildren } from 'react';
import { AuthState, User } from '../types';
import { db } from '../services/db';
import { sendLoginAlert } from '../services/emailService';

const AuthContext = createContext<AuthState | undefined>(undefined);

export const AuthProvider = ({ children }: PropsWithChildren) => {
  const [user, setUser] = useState<User | null>(null);

  // Load user from session (basic persistence for reload)
  useEffect(() => {
      const stored = sessionStorage.getItem('medigen_session_user');
      if (stored) {
          try {
              setUser(JSON.parse(stored));
          } catch (e) {
              console.error("Session parse error", e);
          }
      }
  }, []);

  const login = async (email: string, password: string): Promise<{ success: boolean; error?: string }> => {
    try {
        const loggedUser = await db.authenticateUser(email, password);
        setUser(loggedUser);
        sessionStorage.setItem('medigen_session_user', JSON.stringify(loggedUser));
        await db.logActivity('Login', `User logged in: ${email}`);

        // Trigger Email/SMS Notification
        sendLoginAlert(loggedUser).catch(err => console.error("Failed to send login alert", err));

        return { success: true };
    } catch (e: any) {
        return { success: false, error: e.message || "Login failed" };
    }
  };

  const register = async (name: string, email: string, phone: string, password: string): Promise<{ success: boolean; error?: string }> => {
      try {
          const newUser = await db.registerUser(name, email, phone, password);
          setUser(newUser);
          sessionStorage.setItem('medigen_session_user', JSON.stringify(newUser));

          // Trigger Notification for new registration login
          sendLoginAlert(newUser).catch(err => console.error("Failed to send login alert", err));

          return { success: true };
      } catch (e: any) {
          return { success: false, error: e.message || "Registration failed" };
      }
  };

  const logout = () => {
    if (user) {
        db.logActivity('Logout', `User logged out: ${user.email}`);
    }
    setUser(null);
    sessionStorage.removeItem('medigen_session_user');
  };

  return (
    <AuthContext.Provider value={{ user, isAuthenticated: !!user, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, Lock, Mail, User as UserIcon, Loader2, AlertCircle, ArrowRight, Check, Phone } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
  initialEmail?: string;
}

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose, initialEmail = '' }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState(initialEmail);
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);

  const { login, register } = useAuth();

  useEffect(() => {
    if (isOpen) {
      setEmail(initialEmail || '');
      setPassword('');
      setName('');
      setPhone('');
      setError('');
      if (initialEmail) setIsLogin(true);
    }
  }, [isOpen, initialEmail]);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
        await new Promise(resolve => setTimeout(resolve, 800));

        if (isLogin) {
            const res = await login(email, password);
            if (res.success) {
                onClose();
            } else {
                setError(res.error || "Login failed");
            }
        } else {
            const res = await register(name, email, phone, password);
            if (res.success) {
                onClose();
            } else {
                setError(res.error || "Registration failed");
            }
        }
    } catch (err) {
        setError("An unexpected error occurred.");
    } finally {
        setLoading(false);
    }
  };

  return createPortal(
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-[420px] overflow-hidden animate-slide-up relative flex flex-col max-h-[90vh]">

        {/* Header / Tabs */}
        <div className="relative pt-6 px-6 pb-4 bg-gray-50/50 border-b border-gray-100">
             <button 
              onClick={onClose}
              className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 hover:bg-gray-100 p-2 rounded-full transition-all"
            >
              <X size={20} />
            </button>

            <div className="text-center mb-6">
                 <h2 className="text-2xl font-extrabold text-gray-800 tracking-tight">
                    Medi<span className="text-pastel-primary">Gen</span>
                 </h2>
                 <p className="text-xs text-gray-400 font-medium uppercase tracking-widest mt-1">Healthcare Simplified</p>
            </div>

            <div className="flex p-1 bg-gray-200/50 rounded-xl relative">
                <div 
                    className={`absolute inset-y-1 w-1/2 bg-white rounded-lg shadow-sm transition-all duration-300 ease-out transform ${isLogin ? 'translate-x-0' : 'translate-x-full'}`}
                ></div>
                <button 
                    onClick={() => { setIsLogin(true); setError(''); }}
                    className={`flex-1 relative z-10 py-2.5 text-sm font-bold transition-colors duration-300 ${isLogin ? 'text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Sign In
                </button>
                <button 
                    onClick={() => { setIsLogin(false); setError(''); }}
                    className={`flex-1 relative z-10 py-2.5 text-sm font-bold transition-colors duration-300 ${!isLogin ? 'text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Register
                </button>
            </div>
        </div>

        <div className="p-6 md:p-8 overflow-y-auto">
          {error && (
              <div className="mb-6 p-4 bg-red-50 text-red-600 text-sm rounded-2xl flex items-start gap-3 border border-red-100 animate-fade-in">
                  <AlertCircle size={18} className="shrink-0 mt-0.5" /> 
                  <span className="font-medium">{error}</span>
              </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {!isLogin && (
              <div className="group">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Full Name</label>
                <div className="relative">
                    <UserIcon className="absolute left-4 top-3.5 h-5 w-5 text-gray-400 group-focus-within:text-pastel-primary transition-colors" />
                    <input
                    type="text"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:ring-4 focus:ring-pastel-primary/10 focus:border-pastel-primary outline-none transition-all font-medium text-gray-700 placeholder-gray-400"
                    placeholder="John Doe"
                    />
                </div>
              </div>
            )}

            <div className="group">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-4 top-3.5 h-5 w-5 text-gray-400 group-focus-within:text-pastel-primary transition-colors" />
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:ring-4 focus:ring-pastel-primary/10 focus:border-pastel-primary outline-none transition-all font-medium text-gray-700 placeholder-gray-400"
                  placeholder="name@example.com"
                />
              </div>
            </div>

            {!isLogin && (
              <div className="group">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Phone Number</label>
                <div className="relative">
                    <Phone className="absolute left-4 top-3.5 h-5 w-5 text-gray-400 group-focus-within:text-pastel-primary transition-colors" />
                    <input
                    type="tel"
                    required
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:ring-4 focus:ring-pastel-primary/10 focus:border-pastel-primary outline-none transition-all font-medium text-gray-700 placeholder-gray-400"
                    placeholder="+91 98765 43210"
                    />
                </div>
              </div>
            )}

            <div className="group">
               <div className="flex justify-between items-center mb-1.5 ml-1">
                    <label className="block text-xs font-bold text-gray-500 uppercase">Password</label>
                    {isLogin && (
                        <button type="button" className="text-xs font-bold text-pastel-primary hover:text-pastel-secondary transition-colors">
                            Forgot?
                        </button>
                    )}
               </div>
              <div className="relative">
                <Lock className="absolute left-4 top-3.5 h-5 w-5 text-gray-400 group-focus-within:text-pastel-primary transition-colors" />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:ring-4 focus:ring-pastel-primary/10 focus:border-pastel-primary outline-none transition-all font-medium text-gray-700 placeholder-gray-400"
                  placeholder="••••••••"
                />
              </div>
            </div>

            {isLogin && (
                <label className="flex items-center gap-2 cursor-pointer group">
                    <div className={`w-5 h-5 rounded border flex items-center justify-center transition-all ${rememberMe ? 'bg-pastel-primary border-pastel-primary' : 'bg-white border-gray-300 group-hover:border-pastel-primary'}`}>
                        {rememberMe && <Check size={12} className="text-white" />}
                    </div>
                    <input type="checkbox" className="hidden" checked={rememberMe} onChange={() => setRememberMe(!rememberMe)} />
                    <span className="text-sm text-gray-500 font-medium">Keep me signed in</span>
                </label>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-pastel-primary hover:bg-pastel-secondary text-white font-bold py-4 rounded-xl shadow-xl shadow-teal-500/20 transition-all transform hover:-translate-y-0.5 active:translate-y-0 flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed disabled:transform-none"
            >
              {loading ? (
                  <Loader2 className="animate-spin" size={20} />
              ) : (
                  <>
                    {isLogin ? 'Sign In' : 'Create Account'}
                    <ArrowRight size={18} />
                  </>
              )}
            </button>
          </form>

          {/* Social Divider */}
          <div className="relative my-8">
                <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-gray-200"></div>
                </div>
                <div className="relative flex justify-center text-xs uppercase">
                    <span className="bg-white px-3 text-gray-400 font-bold tracking-wider">Or continue with</span>
                </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
              <button className="flex items-center justify-center gap-2 py-2.5 border border-gray-200 rounded-xl hover:bg-gray-50 hover:border-gray-300 transition-all">
                  <img src="https://www.svgrepo.com/show/475656/google-color.svg" alt="Google" className="w-5 h-5" />
                  <span className="text-sm font-bold text-gray-600">Google</span>
              </button>
              <button className="flex items-center justify-center gap-2 py-2.5 border border-gray-200 rounded-xl hover:bg-gray-50 hover:border-gray-300 transition-all">
                 <img src="https://www.svgrepo.com/show/475647/facebook-color.svg" alt="Facebook" className="w-5 h-5" />
                 <span className="text-sm font-bold text-gray-600">Facebook</span>
              </button>
          </div>

        </div>
      </div>
    </div>,
    document.body
  );
};

export default AuthModal;

