const express = require('express');
const cors = require('cors');
const bodyParser = require('body-parser');
const bcrypt = require('bcryptjs');
const db = require('./database');

const app = express();
const PORT = 5000;

app.use(cors());
app.use(bodyParser.json());

// --- Helper Functions ---

const validateEmail = (email) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(String(email).toLowerCase());
};

const validatePassword = (password) => {
    // Min 8 chars, 1 uppercase, 1 lowercase, 1 number, 1 special character
    const re = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;
    return re.test(password);
};

// --- Auth Routes ---

// Register
app.post('/api/register', async (req, res) => {
    const { name, email, phone, password } = req.body;

    // 1. Basic Field Validation
    if (!name || !email || !password || !phone) {
        return res.status(400).json({ error: "All fields are required" });
    }

    // 2. Email Format Validation
    if (!validateEmail(email)) {
        return res.status(400).json({ error: "Invalid email format." });
    }

    // 3. Restricted Email Check
    if (email.toLowerCase() === 'admin@medigen.com') {
        return res.status(403).json({ error: "Restricted email address." });
    }

    // 4. Password Strength Validation
    if (!validatePassword(password)) {
        return res.status(400).json({ 
            error: "Password must be at least 8 characters long and include 1 uppercase, 1 lowercase, 1 number, and 1 special character." 
        });
    }

    try {
        // 5. Hash Password
        const salt = await bcrypt.genSalt(10);
        const hashedPassword = await bcrypt.hash(password, salt);

        const id = `usr_${Date.now()}`;
        const role = 'user';
        const createdAt = Date.now();

        const sql = `INSERT INTO users (id, name, email, phone, password, role, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)`;

        db.run(sql, [id, name, email, phone, hashedPassword, role, createdAt], function(err) {
            if (err) {
                if (err.message.includes('UNIQUE constraint failed')) {
                    return res.status(400).json({ error: "User already exists with this email." });
                }
                return res.status(500).json({ error: err.message });
            }

            // Return user without password
            res.json({
                id,
                name,
                email,
                phone,
                role,
                createdAt
            });
        });
    } catch (err) {
        res.status(500).json({ error: "Server error during registration." });
    }
});

// Login
app.post('/api/login', (req, res) => {
    const { email, password } = req.body;

    if (!email || !password) {
        return res.status(400).json({ error: "Email and password are required." });
    }

    const sql = `SELECT * FROM users WHERE email = ?`;

    db.get(sql, [email], async (err, row) => {
        if (err) {
            return res.status(500).json({ error: err.message });
        }
        if (!row) {
            return res.status(401).json({ error: "Invalid email or password." });
        }

        // Compare input password with stored hash
        const isMatch = await bcrypt.compare(password, row.password);

        if (!isMatch) {
            return res.status(401).json({ error: "Invalid email or password." });
        }

        // Return user without password
        const { password: _, ...user } = row;
        res.json(user);
    });
});

app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
});

