                  </div>
                  <p className="text-xs text-gray-400">Redirecting to order tracking...</p>
              </div>
          </div>
      )
  }

  return (
    <div className="min-h-screen bg-gray-50 py-10">
      <div className="max-w-4xl mx-auto px-4">
