    const fetchOrderData = async () => {
      setLoading(true);
      if (urlOrderId) {
          const foundOrder = await db.getOrder(urlOrderId);
          setOrder(foundOrder);
      } else {
          setOrder(null);
      }
      setLoading(false);
    };

    fetchOrderData();
  }, [urlOrderId]);

  // Fetch user's orders when on the landing page (no specific ID)
  useEffect(() => {
    const fetchMyOrders = async () => {
        if (isAuthenticated && user?.email && !urlOrderId) {
