                </form>
            </div>

            {/* Split Order History Blocks - Side by Side Grid */}
            {isAuthenticated && (myOrders.length > 0) && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-start animate-fade-in">

                    {/* Live Orders Block */}
                    {liveOrders.length > 0 && (
