                {order.status === 'delivered' ? <Check size={12}/> : 
                 order.status === 'rejected' ? <XCircle size={12}/> :
                 <div className="w-1.5 h-1.5 bg-blue-500 rounded-full"></div>} 
                {order.status.replace('_', ' ')}
