        </div>

        <Link to="/track-order" onClick={() => setOrder(null)} className="block w-full text-center py-4 text-gray-400 hover:text-pastel-primary font-medium text-sm transition-colors">
            Track Another Order
        </Link>

      </div>
    </div>
  );
};

